// Pega o primeiro item do array retornado pela planilha
const dados = $input.item.json;

// Retorna apenas os campos necessários
return {
  json: {
    Titulo: dados.Titulo,
    Briefing: dados.Briefing || '',
    Blog: dados.Blog,
    Legenda_Instagram: dados.Legenda_Instagram
  }
};

// Inicializa o array que armazenará os resultados processados
const results = [];

for (const item of $input.all()) {
  try {
    // 1️⃣ Pega o texto completo retornado pela IA
    const rawOutput = item.json.output;

    // 2️⃣ Remove possíveis marcações de bloco de código (```json ... ```) ou espaços extras
    const cleanJson = rawOutput
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    // 3️⃣ Faz o parsing do JSON interno gerado pela IA
    const parsed = JSON.parse(cleanJson);

    // 4️⃣ Retorna todos os campos estruturados em formato limpo e utilizável
    results.push({
      json: {
        query_unsplash: parsed.query_unsplash,
        texto_imagem_principal: parsed.texto_imagem_principal,
        texto_imagem_secundario: parsed.texto_imagem_secundario,
        legenda_linkedin: parsed.legenda_linkedin,
      },
    });
  } catch (error) {
    // 5️⃣ Caso ocorra erro, retorna o erro junto com o conteúdo original
    results.push({
      json: {
        error: error.message,
        raw_output: item.json.output,
      },
    });
  }
}

// 6️⃣ Retorna o resultado final para o fluxo
return results;

// --- Captura a resposta do Unsplash e a query original ---
const results = $json.results || [];
const queryKey = Object.keys($json).find(k => k.startsWith('query_slide_'));
const originalQuery = queryKey ? $json[queryKey] : ($json.query || '');

// --- Seleciona uma imagem aleatória ou o único resultado ---
const randomIndex = results.length > 0 ? Math.floor(Math.random() * results.length) : 0;
const selectedImage = results[randomIndex] || $json;

// --- Extrai a melhor URL disponível ---
const imageUrl = selectedImage.urls?.regular ||
                 selectedImage.urls?.small ||
                 selectedImage.urls?.raw || '';

// --- Retorna apenas as informações necessárias ---
return {
  json: {
    unsplash_url: imageUrl,                                 // URL principal da imagem
    unsplash_download: selectedImage.links?.download || '',  // Link direto para download
    original_query: originalQuery,                           // Query usada na busca
    image_data: selectedImage                                // Dados brutos para depuração
  }
};

