<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=1080, height=1350" />
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@600;700;800;900&family=Space+Grotesk:wght@700&display=swap" rel="stylesheet">
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    html, body {
      width: 1080px;
      height: 1350px;
      font-family: 'Inter', sans-serif;
      overflow: hidden;
      position: relative;
      background: #0a0a0a;
    }

    .image-container {
      position: relative;
      width: 100%;
      height: 100%;
      overflow: hidden;
      background: linear-gradient(135deg, #0a0a0a 0%, #1a1510 100%);
    }

    .image-container::before {
      content: "";
      position: absolute;
      inset: 0;
      background-image: url("{{ $json.unsplash_url }}");
      background-size: cover;
      background-position: center;
      filter: brightness(0.35) saturate(1.2);
      z-index: 1;
    }

    /* Efeito de grade tecnológica */
    .grid-overlay {
      position: absolute;
      inset: 0;
      background-image: 
        linear-gradient(rgba(255, 174, 66, 0.03) 1px, transparent 1px),
        linear-gradient(90deg, rgba(255, 174, 66, 0.03) 1px, transparent 1px);
      background-size: 50px 50px;
      z-index: 2;
      opacity: 0.4;
    }

    /* Gradiente escuro superior */
    .overlay-top {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 40%;
      background: linear-gradient(to bottom, rgba(10,10,10,0.95), transparent);
      z-index: 3;
    }

    /* Gradiente escuro inferior mais forte */
    .overlay-bottom {
      position: absolute;
      bottom: 0;
      left: 0;
      width: 100%;
      height: 55%;
      background: linear-gradient(to top, rgba(10,10,10,0.98), transparent);
      z-index: 3;
    }

    /* Efeito de luz neon */
    .neon-glow {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 800px;
      height: 800px;
      background: radial-gradient(circle, rgba(255, 174, 66, 0.15) 0%, transparent 70%);
      z-index: 2;
      animation: pulse 4s ease-in-out infinite;
    }

    @keyframes pulse {
      0%, 100% { opacity: 0.3; transform: translate(-50%, -50%) scale(1); }
      50% { opacity: 0.5; transform: translate(-50%, -50%) scale(1.1); }
    }

    /* Logo com glassmorphism */
    .logo-container {
      position: absolute;
      top: 60px;
      right: 60px;
      z-index: 10;
      background: rgba(255, 255, 255, 0.05);
      backdrop-filter: blur(20px);
      border: 1px solid rgba(255, 174, 66, 0.3);
      border-radius: 20px;
      padding: 25px 35px;
      box-shadow: 0 8px 32px rgba(255, 174, 66, 0.2);
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .logo-text {
      font-size: 52px;
      font-weight: 900;
      font-family: 'Space Grotesk', monospace;
      background: linear-gradient(135deg, #FFAE42 0%, #FF8C42 50%, #FF6B35 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
      letter-spacing: 2px;
      line-height: 1;
      text-shadow: 0 0 30px rgba(255, 174, 66, 0.5);
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .logo-cursor {
      display: inline-block;
      width: 4px;
      height: 48px;
      background: #FFAE42;
      animation: blink 1s infinite;
      box-shadow: 0 0 10px #FFAE42;
    }

    @keyframes blink {
      0%, 49% { opacity: 1; }
      50%, 100% { opacity: 0; }
    }

    /* Texto principal com glassmorphism */
    .text-block {
      position: absolute;
      bottom: 180px;
      left: 0;
      right: 0;
      padding: 0 70px;
      z-index: 10;
      max-height: 500px;
    }

    .glass-container {
      background: rgba(15, 15, 25, 0.6);
      backdrop-filter: blur(30px);
      border: 1px solid rgba(255, 174, 66, 0.3);
      border-radius: 30px;
      padding: 50px;
      box-shadow: 
        0 8px 32px rgba(0, 0, 0, 0.4),
        inset 0 1px 0 rgba(255, 255, 255, 0.1);
      position: relative;
      overflow: hidden;
    }

    .glass-container::before {
      content: "";
      position: absolute;
      top: -2px;
      left: -2px;
      right: -2px;
      bottom: -2px;
      background: linear-gradient(135deg, rgba(255, 174, 66, 0.3), rgba(255, 107, 53, 0.3));
      border-radius: 30px;
      z-index: -1;
      opacity: 0.5;
    }

    /* TEXTO PRINCIPAL - MAIOR E CHAMATIVO */
    .text-block h1 {
      font-size: 64px;
      font-weight: 900;
      line-height: 1.15;
      letter-spacing: -1.5px;
      font-family: 'Inter', sans-serif;
      color: #ffffff;
      text-align: left;
      margin-bottom: 25px;
      position: relative;
      text-shadow: 
        0 0 20px rgba(255, 174, 66, 0.3),
        2px 2px 10px rgba(0, 0, 0, 0.8);
    }

    .text-block h1 .highlight {
      background: linear-gradient(135deg, #FFAE42 0%, #FF8C42 50%, #FF6B35 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
      font-weight: 900;
      display: inline;
      position: relative;
    }

    .text-block h1 .highlight::after {
      content: "";
      position: absolute;
      bottom: -8px;
      left: 0;
      width: 100%;
      height: 4px;
      background: linear-gradient(90deg, #FFAE42, #FF6B35);
      box-shadow: 0 0 15px rgba(255, 174, 66, 0.8);
    }

    /* TEXTO SECUNDÁRIO - MENOR E EXPLICATIVO */
    .text-block p {
      font-size: 28px;
      font-weight: 600;
      line-height: 1.4;
      letter-spacing: -0.5px;
      font-family: 'Inter', sans-serif;
